// =============================================================================
// Eval Runner + Stats Aggregator
//
// 1. Decodes eval set and system prompt from GitHub API response
// 2. Runs every eval case against the Akinator (game loop per case)
// 3. Computes quality stats
// 4. Extracts any existing quality baseline from the system prompt header
// 5. Builds updated system prompt with new quality score prepended
//
// Requires env var: OPENROUTER_API_KEY
// Optional env var: EVAL_MODEL
// =============================================================================

const trigger = $('Execute Workflow Trigger').item.json;
const evalFileData = $('Fetch Eval Set').item.json;
const promptFileData = $('Fetch System Prompt').item.json;

// --- Decode eval set ---
const evalB64 = (evalFileData.content || '').replace(/\n/g, '');
const evalJson = Buffer.from(evalB64, 'base64').toString('utf8');
let evals;
try { evals = JSON.parse(evalJson); } catch(e) { throw new Error('Could not parse eval set: ' + e.message); }

// --- Decode system prompt ---
const promptB64 = (promptFileData.content || '').replace(/\n/g, '');
const currentPrompt = Buffer.from(promptB64, 'base64').toString('utf8');
const promptFileSha = promptFileData.sha;
const promptPath = trigger.system_prompt_path || 'agents/akinator/system-prompt.md';

// Strip any existing quality header so we run against the clean prompt
const cleanPrompt = currentPrompt.replace(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/g, '').trim();

// --- Extract baseline stats from existing header (if any) ---
let baseline = null;
const headerMatch = currentPrompt.match(/<!--\s*QUALITY_SCORE([\s\S]*?)-->/);
if (headerMatch) {
  try { baseline = JSON.parse(headerMatch[1].trim()); } catch(e) { /* non-fatal */ }
}

// --- Game simulation ---
const model = $env.EVAL_MODEL || 'google/gemini-2.5-flash-preview';
const apiKey = $env.OPENROUTER_API_KEY;
if (!apiKey) throw new Error('OPENROUTER_API_KEY is not set in n8n environment variables');

const maxIter = trigger.max_iterations || 40;
const BASE_URL = 'https://openrouter.ai/api/v1/chat/completions';

const callLLM = async (messages, sysOverride) => {
  const payload = {
    model: model,
    temperature: 0.1,
    messages: sysOverride
      ? [{ role: 'system', content: sysOverride }].concat(messages)
      : messages
  };
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: BASE_URL,
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload)
  });
  return {
    text: res.choices[0].message.content.trim(),
    tokens: (res.usage || {}).total_tokens || 0
  };
};

const runGame = async (evalCase) => {
  const userSim = [
    'You are roleplaying as a user in a guessing game. Your scenario: ' + evalCase.context + '.',
    'Your mindset going into the game: ' + evalCase.thoughts,
    '',
    'Rules:',
    '- Answer every question from the host with ONLY one of: Yes / No / Unknown / Probably / Probably not',
    '- Use your knowledge of the character described in your scenario to answer accurately',
    '- If the host makes a direct guess naming a character, reply Yes only if that is the character in your scenario, otherwise No',
    '- Never reveal the character name or any identifying detail unprompted \u2014 only confirm or deny explicit guesses'
  ].join('\n');

  const hist = [
    { role: 'system', content: cleanPrompt },
    { role: 'user', content: evalCase.chatMessage }
  ];
  let iter = 0, success = false, tokens = 0;

  while (iter < maxIter) {
    const akResp = await callLLM(hist);
    tokens += akResp.tokens;
    hist.push({ role: 'assistant', content: akResp.text });
    iter++;

    const isGuess = /is your character|are you thinking of|i think it.s|i believe it.*is|my answer is|i have reached/i.test(akResp.text);

    const userResp = await callLLM(
      [{ role: 'user', content: akResp.text }],
      userSim
    );
    tokens += userResp.tokens;
    hist.push({ role: 'user', content: userResp.text });

    if (isGuess && userResp.text.trim().toLowerCase().startsWith('yes')) {
      success = true;
      break;
    }
  }
  return { character: evalCase.character, iterations: iter, success: success, tokens_used: tokens };
};

// Run all evals sequentially
const results = [];
for (const evalCase of evals) {
  const r = await runGame(evalCase);
  results.push(r);
}

// --- Aggregate stats ---
const successes = results.filter(function(r) { return r.success; });
const successRate = Math.round((successes.length / results.length) * 1000) / 10;
const avgIter = Math.round(results.reduce(function(s, r) { return s + r.iterations; }, 0) / results.length * 10) / 10;
const totalTokens = results.reduce(function(s, r) { return s + r.tokens_used; }, 0);
const tokensPerGame = Math.round(totalTokens / results.length);
const evaluatedAt = new Date().toISOString();

const newStats = {
  model: model,
  total_games: results.length,
  successful_games: successes.length,
  success_rate: successRate,
  avg_iterations: avgIter,
  total_tokens: totalTokens,
  tokens_per_game: tokensPerGame,
  evaluated_at: evaluatedAt
};

// --- Quality comparison ---
// When no baseline exists (first run) we fall back to minimum acceptable
// thresholds rather than failing silently. Callers can override the defaults
// by passing min_success_rate and max_avg_iterations as trigger inputs.
const minRate = trigger.min_success_rate !== undefined ? parseFloat(trigger.min_success_rate) : 50;
const maxIters = trigger.max_avg_iterations !== undefined ? parseFloat(trigger.max_avg_iterations) : 30;

const firstRun = !baseline;
let improved = false;

if (firstRun) {
  // No prior score to compare against. Promote if score clears the floor thresholds.
  improved = successRate >= minRate && avgIter <= maxIters;
} else {
  // Subsequent runs: both metrics must strictly improve vs the recorded baseline.
  const oldRate = parseFloat(baseline.success_rate || 0);
  const oldIter = parseFloat(baseline.avg_iterations || 999);
  improved = successRate > oldRate && avgIter < oldIter;
}

newStats.first_run = firstRun;
newStats.thresholds_used = firstRun ? { min_success_rate: minRate, max_avg_iterations: maxIters } : null;

// --- Build updated system prompt with quality header ---
const qualityHeader = '<!-- QUALITY_SCORE\n' + JSON.stringify(newStats, null, 2) + '\n-->\n\n';
const updatedPrompt = qualityHeader + cleanPrompt;

return [{ json: {
  results: results,
  stats: newStats,
  baseline: baseline,
  first_run: firstRun,
  improved: improved,
  updatedPrompt: updatedPrompt,
  promptFileSha: promptFileSha,
  promptPath: promptPath,
  owner: trigger.owner,
  repo: trigger.repo,
  branch: trigger.branch,
  pr_number: trigger.pr_number
}}];

const data = $input.item.json;

const body = {
  message: 'chore: add quality score to system prompt [auto-eval]',
  content: Buffer.from(data.updatedPrompt).toString('base64'),
  branch: data.branch,
  sha: data.promptFileSha
};

return [{ json: {
  commitBody: JSON.stringify(body),
  owner: data.owner,
  repo: data.repo,
  promptPath: data.promptPath,
  stats: data.stats,
  improved: data.improved,
  pr_number: data.pr_number
}}];
